INSERT INTO `blogs` (`id`, `title`, `slug`, `excerpt`, `description`, `image`, `author`, `created_at`, `updated_at`) VALUES
(15, 'Empowering Women: A Joyous Women\'s Day Celebration', 'empowering-women-a-joyous-womens-day-celebration', 'International Women\'s Day is a time to honor the achievements, strength, and resilience of women across the globe. Our Women\'s Day celebration was filled with enthusiasm, recognition, and heartfelt appreciation for the incredible women who inspire us ever', '[{\"data\": {\"content\": \"<p>International Women\'s Day is a time to honor the achievements, strength, and resilience of women across the globe. Our Women\'s Day celebration was filled with enthusiasm, recognition, and heartfelt appreciation for the incredible women who inspire us every day.</p><p>The event kicked off with an inspiring keynote speech highlighting the importance of gender equality and women\'s empowerment. It was followed by engaging activities, including motivational talks, cultural performances, and fun team-building games. A special segment was dedicated to honoring outstanding women for their contributions in various fields.</p><p>Adding to the celebration, interactive workshops on self-care, leadership, and professional growth provided valuable insights for all attendees. The day concluded with a pledge to continue supporting and uplifting women in all walks of life.</p><p>Women\'s Day is not just a celebration; it\'s a reminder of the progress made and the journey ahead. Let\'s continue to support, empower, and uplift each other every day!</p>\"}, \"type\": \"Rich Editor\"}, {\"data\": {\"alt\": \"Image\", \"url\": [\"file-manager/blog/images/IMG_20250310_184454.jpg\", \"file-manager/blog/images/IMG_20250310_184518.jpg\"]}, \"type\": \"Multiple Images\"}]', 'file-manager/blog/feature-image/01JP2H7C415TGVCT5WN9W3VEKA.jpg', NULL, '2025-03-11 06:30:15', '2025-03-11 06:30:15'),
(16, 'BICS 25 Years Silver Jubilee', 'bics-25-years-silver-jubilee', '(BICS_25 Years of Youth Services in Don Bosco Way with Fr Guezou!!!) ', '[{\"data\": {\"content\": \"<p>Wth the blessings of the Heavenly Father, Our Lord Jesus Christ, and the guiding spirit of Don Bosco and Fr. Guezou, Don Bosco Centre, Yelagiri Hills continues to impact the lives of many rural and tribal youth. This year marks the 25th anniversary of our commitment to empowering rural youth through IT education, training, and placement – a vision pioneered by Fr. Francis Guezou as BICS InfoTech. Our college is making steady progress, in spite of a few challenges. We offer 7 undergraduate and 2 postgraduate programs of study with a student community of 1160.</p><p><br></p><p><a href=\\\"https://youtu.be/u6SKg-u2nKw?si=JVj6JeilE928Kiv4\\\"><strong>Watch video</strong></a></p>\"}, \"type\": \"Rich Editor\"}]', 'file-manager/blog/feature-image/01JPJB6Q7YTTN56YY5R4QQHMD8.png', 'Admin', '2025-03-17 09:52:53', '2025-03-17 09:53:50'),
(17, 'Nation Level Hands-on Training on Up-scaling Pedagogy with MOODLE', 'nation-level-hands-on-training-on-up-scaling-pedagogy-with-moodle', 'Nation Level Hands-on Training on Up-scaling Pedagogy with MOODLE || Don Bosco College || BoscoSoft', '[{\"data\": {\"content\": \"<p>Nation Level Hands-on&nbsp; Training on&nbsp; MOODLE provides hands-on experience with Moodle to upscale the teaching-learning process by experienced practitioners of Moodle as Learning Management System</p><p><br></p><p><a href=\\\"https://youtu.be/D_TqQGj4AaQ?si=qFD_C7_gyJ6l5v2V\\\"><strong>Watch Video</strong></a></p>\"}, \"type\": \"Rich Editor\"}]', 'file-manager/blog/feature-image/01JPJBBR2J88CTCHNQK0765GWN.png', 'Admin', '2025-03-17 09:55:37', '2025-03-17 09:55:37'),
(18, 'Technology  Certification Course - Success of TechTalk', 'technology-certification-course-success-of-techtalk', 'TechTalk is a Three-Months technology advancement program for IT amateurs who have done their graduation or post-graduation in Computer Science, Computer Applications or Computer Engineering. This is conducted by BOSCOITS, the Technology Resource Centre o', '[{\"data\": {\"content\": \"<p>TechTalk is a Three-Months technology advancement program for IT amateurs who have done their graduation or post-graduation in Computer Science, Computer Applications or Computer Engineering. This is conducted by BOSCOITS, the Technology Resource Centre of BICS InfoTech. This institute has twenty-two years of experience in training and placement of IT graduates in the industry with the required skills and exposure. TECHTALK Transforms Students into Experts. It makes sure that you get a job.<br>If you are intending to:<br>• Sharpen your development and technical skills;<br>• Choose a career option in a technology domain; and<br>• Update on .Net Core, Java, Android IOT &amp; IOS, LAMP, Python, Process Maker, and Technical Writing<br>TechTalk is a fitting program.</p><p><br></p><p><a href=\\\"https://youtu.be/KDD20yqC3WU?si=c0rkdJMbfZF7wjfh\\\"><strong>Watch Video</strong></a></p>\"}, \"type\": \"Rich Editor\"}]', 'file-manager/blog/feature-image/01JPJBGKKWXQETBJ1Q3Z1X5SQR.png', 'Admin', '2025-03-17 09:58:17', '2025-03-17 09:58:17'),
(19, 'AI -Tracking Academic Progress in an Intelligent Way', 'ai-tracking-academic-progress-in-an-intelligent-way', 'From Reports to Predictions” is the new way of tracking the academic progress of students using Artificial Intelligence (AI). It helps Schools Track Academic Progress More effectively and highlights how artificial intelligence (AI) is changing the way ', '[{\"data\": {\"content\": \"<p>\\\"<em>From Reports to Predictions” is the new way of tracking the academic progress of students using Artificial Intelligence (AI). It helps Schools Track Academic Progress More effectively and highlights how artificial intelligence (AI) is changing the way schools monitor student progress.</em></p><p><strong>It covers the following key aspects:</strong></p><p><strong>Introduction:&nbsp; </strong>AI is replacing traditional methods of measuring student progress.</p><p><strong>How AI Transforms Academic Tracking:&nbsp;</strong></p><ul><li>Real-time performance monitoring with dashboards.</li><li>Predictive analytics for early intervention.</li><li>Personalized learning paths.</li><li>Automated grading and feedback.</li></ul><p><strong>AI-Powered Dashboards &amp; Reports:</strong> AI lists student progress charts, performance heatmaps, and predictive score analysis, with a link to an example dashboard image.</p><p><strong>Comparison with Traditional Methods:&nbsp; </strong>It provides a table comparing traditional and AI-powered tracking in terms of data processing, intervention timing, personalization, and feedback speed.</p><p><strong>The Future of AI in Education:</strong> This emphasizes that AI is about empowering educators and helping students succeed.</p><p><strong>Virtual Tutors: </strong>More sophisticated AI tutors that can provide personalized support outside of regular classroom hours.</p><p><strong>AI-Driven Curriculum Development: </strong>AI may help design and update curricula more dynamically, adapting to the latest educational research and student needs.</p><p><strong>Augmented Reality (AR) and Virtual Reality (VR) Integration: </strong>AI will likely play a key role in enhancing AR/VR learning experiences, making education more immersive and engaging.\\\"</p><p><br></p><p><br></p>\"}, \"type\": \"Rich Editor\"}]', 'file-manager/blog/feature-image/01JYZMV9VZ723FKY9TRPJJ4YX6.jpg', NULL, '2025-06-29 23:34:33', '2025-11-02 23:43:07');
